import AsyncStorage from '@react-native-async-storage/async-storage';

const BASE_URL = 'https://api.example.com';
const TOKEN_KEY = '@auth_token';
const REFRESH_TOKEN_KEY = '@refresh_token';

class ApiService {
  constructor() {
    this.baseUrl = BASE_URL;
    this.token = null;
    this.refreshToken = null;
  }

  async init() {
    this.token = await AsyncStorage.getItem(TOKEN_KEY);
    this.refreshToken = await AsyncStorage.getItem(REFRESH_TOKEN_KEY);
  }

  async setTokens(token, refreshToken) {
    this.token = token;
    this.refreshToken = refreshToken;
    await AsyncStorage.setItem(TOKEN_KEY, token);
    if (refreshToken) {
      await AsyncStorage.setItem(REFRESH_TOKEN_KEY, refreshToken);
    }
  }

  async clearTokens() {
    this.token = null;
    this.refreshToken = null;
    await AsyncStorage.removeItem(TOKEN_KEY);
    await AsyncStorage.removeItem(REFRESH_TOKEN_KEY);
  }

  async request(endpoint, options = {}) {
    const url = `${this.baseUrl}${endpoint}`;
    const headers = {
      'Content-Type': 'application/json',
      ...options.headers,
    };

    if (this.token && !options.skipAuth) {
      headers['Authorization'] = `Bearer ${this.token}`;
    }

    const config = {
      ...options,
      headers,
    };

    if (options.body && typeof options.body === 'object') {
      config.body = JSON.stringify(options.body);
    }

    try {
      const response = await fetch(url, config);

      if (response.status === 401 && !options.skipRefresh) {
        const refreshed = await this.refreshAccessToken();
        if (refreshed) {
          return this.request(endpoint, { ...options, skipRefresh: true });
        } else {
          await this.clearTokens();
          throw new Error('Session expired. Please login again.');
        }
      }

      const contentType = response.headers.get('content-type');
      let data;
      
      if (contentType && contentType.includes('application/json')) {
        data = await response.json();
      } else {
        data = await response.text();
      }

      if (!response.ok) {
        throw {
          status: response.status,
          message: data.message || data.error || 'Request failed',
          data: data,
        };
      }

      return data;
    } catch (error) {
      if (error.message === 'Network request failed') {
        throw new Error('Network error. Please check your connection.');
      }
      throw error;
    }
  }

  async refreshAccessToken() {
    if (!this.refreshToken) {
      return false;
    }

    try {
      const response = await this.request('/auth/refresh', {
        method: 'POST',
        body: { refreshToken: this.refreshToken },
        skipAuth: true,
        skipRefresh: true,
      });

      if (response.token) {
        await this.setTokens(response.token, response.refreshToken || this.refreshToken);
        return true;
      }
      return false;
    } catch (error) {
      return false;
    }
  }

  async login(email, password) {
    const response = await this.request('/auth/login', {
      method: 'POST',
      body: { email, password },
      skipAuth: true,
    });

    if (response.token) {
      await this.setTokens(response.token, response.refreshToken);
    }

    return response;
  }

  async register(userData) {
    const response = await this.request('/auth/register', {
      method: 'POST',
      body: userData,
      skipAuth: true,
    });

    if (response.token) {
      await this.setTokens(response.token, response.refreshToken);
    }

    return response;
  }

  async logout() {
    try {
      await this.request('/auth/logout', {
        method: 'POST',
      });
    } catch (error) {
      console.error('Logout error:', error);
    } finally {
      await this.clearTokens();
    }
  }

  async getUserProfile() {
    return this.request('/user/profile', {
      method: 'GET',
    });
  }

  async updateUserProfile(profileData) {
    return this.request('/user/profile', {
      method: 'PUT',
      body: profileData,
    });
  }

  async updateUserAvatar(imageUri) {
    const formData = new FormData();
    const filename = imageUri.split('/').pop();
    const match = /\.(\w+)$/.exec(filename);
    const type = match ? `image/${match[1]}` : 'image/jpeg';

    formData.append('avatar', {
      uri: imageUri,
      name: filename,
      type,
    });

    return this.request('/user/avatar', {
      method: 'POST',
      headers: {
        'Content-Type': 'multipart/form-data',
      },
      body: formData,
    });
  }

  async changePassword(currentPassword, newPassword) {
    return this.request('/user/change-password', {
      method: 'POST',
      body: { currentPassword, newPassword },
    });
  }

  async deleteAccount() {
    const response = await this.request('/user/account', {
      method: 'DELETE',
    });
    await this.clearTokens();
    return response;
  }

  async forgotPassword(email) {
    return this.request('/auth/forgot-password', {
      method: 'POST',
      body: { email },
      skipAuth: true,
    });
  }

  async resetPassword(token, newPassword) {
    return this.request('/auth/reset-password', {
      method: 'POST',
      body: { token, newPassword },
      skipAuth: true,
    });
  }

  async verifyEmail(token) {
    return this.request('/auth/verify-email', {
      method: 'POST',
      body: { token },
      skipAuth: true,
    });
  }

  async getData(endpoint, params = {}) {
    const queryString = Object.keys(params)
      .map(key => `${encodeURIComponent(key)}=${encodeURIComponent(params[key])}`)
      .join('&');
    
    const url = queryString ? `${endpoint}?${queryString}` : endpoint;
    
    return this.request(url, {
      method: 'GET',
    });
  }

  async postData(endpoint, data) {
    return this.request(endpoint, {
      method: 'POST',
      body: data,
    });
  }

  async putData(endpoint, data) {
    return this.request(endpoint, {
      method: 'PUT',
      body: data,
    });
  }

  async patchData(endpoint, data) {
    return this.request(endpoint, {
      method: 'PATCH',
      body: data,
    });
  }

  async deleteData(endpoint) {
    return this.request(endpoint, {
      method: 'DELETE',
    });
  }

  isAuthenticated() {
    return !!this.token;
  }

  getToken() {
    return this.token;
  }
}

const apiService = new ApiService();

export default apiService;